	.TITLE	VISUPART	.PROC	M680002	.RADIX	10.	.HEX	.REF	DRIVERS	.REF	LIB	.REF	SM8	.REF	NTREL	.REF	GESMEM	.REF	FOS	.LOC	0OBUNAME:.BLKB	32OBUDATA:.BLKB	20000LGVAR:	.LOC	0START:;;?	.W	LIB,?OPELIB	LOAD.L	D4,#LGVAR	LOAD.W	D1,#MTYPCP	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE ERFAT	LOAD.L	A6,A4		; A6 <-- ^variables05$:	CLR.B	(A4+)		; met TOUTES les variables  zro	DEC.W	D4	JUMP,NE 05$	.W	LIB,?AFTIM	.ASCIZ	"<CR>Nom du fichier .PART : "	.EVEN	LOAD.L	A3,#(A6)+OBUNAME	LOAD.W	D3,#32	.W	LIB,?GETLINE	.W	LIB,?AFCR	LOAD.W	D3,#2^BOPRD	.W	FOS,?OPEN	JUMP,NE ERROR	LOAD.L	A4,#(A6)+OBUDATA	LOAD.L	D4,#20000	.W	FOS,?RDBYTE	.W	FOS,?CLOSE	JUMP	JOLINEW:	LOAD.L	A3,#R16"TXNAME	.W	FOS,?DELETE	LOAD.L	D3,#DEFATT	LOAD.W	D4,#TYPRAND	.W	FOS,?CREATE	JUMP,NE ERROR	LOAD.W	D3,#2^BOPWR!2^BOPEXCL	.W	FOS,?OPEN	JUMP,NE ERROR	LOAD.L	D4,#H'275A	.W	FOS,?WRBYTE	JUMP,NE ERROR	.W	FOS,?CLOSE	JUMP	FINIJOLI:	LOAD.L	A3,A4	LOAD.L	D3,D4	ADD.L	A3,#256*3	SUB.L	D3,#256*3	CLR.L	D0LOOP:	TEST.W	D3	JUMP,LE FINI	COMP.B	(A3)+2,#H'80	JUMP,NE 20$	.W	LIB,?AFCR	INC.L	D0	PUSHM.L	D2..D4	.W	LIB,?AFSPACE	LOAD.L	D4,D0	LOAD.W	D3,#3	CLR.W	D2	.W	LIB,?AFDEC	.W	LIB,?AFTIM	.ASCIZ	": "	.EVEN	POPM.L	D2..D420$:	LOAD.W	D2,(A3+)	LOAD.W	D4,D2	.W	LIB,?AFX4	.W	LIB,?AFTIM	.ASCIZ	"-"	.EVEN	PUSHM.L	D2..D4	CLR.L	D4	LOAD.B	D4,(A3)	LOAD.W	D3,#3	CLR.W	D2	.W	LIB,?AFDEC	.W	LIB,?AFSPACE	POPM.L	D2..D4	ADD.W	A3,D2	SUB.W	D3,D2	SUB.W	D3,#2	JUMP	LOOPERROR:	.W	LIB,?AFERROR	.W	LIB,?GETCAR	JUMP	ERFATFINI:	.W	LIB,?AFTIM	.ASCIZ	"<CR>Appuyez sur une touche pour sortir ..."	.EVEN	.W	LIB,?GETCARERFAT:;;?	.W	LIB,?CLOLIB;;?	.W	FOS,?STOP	EXITTXNAME:	.ASCIZ	"T.PART"	.EVEN	.END	START